class Animal {
    Animal() {
        System.out.println("Animal constructor");
    }
}

class Dog extends Animal {
    Dog() {
        // implicit: super() → runs Animal()
        System.out.println("Dog constructor");
    }
}

class Labrador extends Dog {
    Labrador() {
        // implicit: super() → runs Dog() which runs Animal()
        System.out.println("Labrador constructor");
    }
}

public class ConstructorOrder {
    public static void main(String[] args) {
        Labrador lab = new Labrador();
        // Output:
        // Animal constructor
        // Dog constructor
        // Labrador constructor
    }
}

class Shape {
    String name = "Shape";
    void draw() { System.out.println("Drawing Shape"); }
    static void info() { System.out.println("Shape info"); }
}

class Circle extends Shape {
    String name = "Circle";  // field HIDING (not overriding)
    @Override
    void draw() { System.out.println("Drawing Circle"); }  // overriding
    static void info() { System.out.println("Circle info"); } // hiding
}

public class DispatchDemo {
    public static void main(String[] args) {
        Shape s = new Circle(); // ref=Shape, actual=Circle

        s.draw();        // Dynamic dispatch → Circle.draw()  → "Drawing Circle"
        Shape.info();    // Static: reference type → "Shape info"
        Circle.info();   // Static: class name used → "Circle info"
        s.info();        // Static: reference type (Shape) → "Shape info"
        System.out.println(s.name); // Field: reference type (Shape) → "Shape"

        Circle c = (Circle) s;
        System.out.println(c.name); // Field: reference type (Circle) → "Circle"
        c.draw();        // Dynamic dispatch → Circle.draw() → "Drawing Circle"
    }
}

class Vehicle {
    String type;
    Vehicle(String type) {
        this.type = type;
        System.out.println("Vehicle: " + type);
    }
    void describe() {
        System.out.println("A vehicle of type: " + type);
    }
}

class Car extends Vehicle {
    int doors;
    Car(int doors) {
        super("Car");  // must be first statement; calls Vehicle("Car")
        this.doors = doors;
        System.out.println("Car with " + doors + " doors");
    }
    @Override
    void describe() {
        super.describe();  // calls Vehicle.describe() explicitly
        System.out.println("Doors: " + doors);
    }
}

public class SuperDemo {
    public static void main(String[] args) {
        Car c = new Car(4);
        // Prints:
        // Vehicle: Car
        // Car with 4 doors
        c.describe();
        // Prints:
        // A vehicle of type: Car
        // Doors: 4
    }
}

class Base {
    int x = 10;
    Base() {
        System.out.println("Base constructor, x=" + x);
        show(); // dynamic dispatch: calls child's show() if overridden!
    }
    void show() {
        System.out.println("Base.show(), x=" + x);
    }
}

class Derived extends Base {
    int y = 20;
    Derived() {
        // implicit super() → runs Base()
        System.out.println("Derived constructor, y=" + y);
    }
    @Override
    void show() {
        // y is NOT yet initialized when called from Base()
        System.out.println("Derived.show(), y=" + y);
    }
}

public class TrickyConstructor {
    public static void main(String[] args) {
        Derived d = new Derived();
    }
    // Output:
    // Base constructor, x=10
    // Derived.show(), y=0   ← y is 0! Derived constructor hasn't run yet
    // Derived constructor, y=20
}

class Animal { void speak() { System.out.println("..."); } }
class Dog extends Animal {
    @Override void speak() { System.out.println("Woof"); }
    void fetch() { System.out.println("Fetching!"); }
}
class Cat extends Animal {
    @Override void speak() { System.out.println("Meow"); }
}

public class CastingDemo {
    public static void main(String[] args) {
        Animal a = new Dog();   // upcast: always safe
        a.speak();              // "Woof" (dynamic dispatch)
        // a.fetch();           // COMPILE ERROR: fetch() not in Animal

        Dog d = (Dog) a;        // downcast: safe because actual type IS Dog
        d.fetch();              // "Fetching!"

        Animal b = new Cat();
        // Dog bad = (Dog) b;   // COMPILES, but throws ClassCastException at runtime!

        if (b instanceof Dog) { // false
            Dog safe = (Dog) b;
        } else {
            System.out.println("b is not a Dog"); // prints this
        }

        // Java 16+ pattern matching:
        if (b instanceof Cat c) {
            c.speak(); // "Meow" — c is already cast inside the block
        }
    }
}

class Point {
    int x, y, z;
    Point() {
        this(0, 0);           // calls Point(int, int)
        System.out.println("Point()");
    }
    Point(int x, int y) {
        this(x, y, 0);        // calls Point(int, int, int)
        System.out.println("Point(" + x + "," + y + ")");
    }
    Point(int x, int y, int z) {
        this.x = x; this.y = y; this.z = z;
        System.out.println("Point(" + x + "," + y + "," + z + ")");
    }
}

public class ThisChainDemo {
    public static void main(String[] args) {
        Point p = new Point();
        // Output:
        // Point(0,0,0)
        // Point(0,0)
        // Point()
    }
}

