// Define an abstract class Shape with an abstract method area().
// Subclasses: Circle (radius), Rectangle (width, height).
// Write a method printArea(Shape s) that uses polymorphism.
// In main, create a Shape[] of mixed objects and call printArea on each.
// Expected output (for r=5, w=4 h=3):
// Circle area: 78.54
// Rectangle area: 12.0

sections.solution:
public class ShapeHierarchy {
    abstract static class Shape {
        abstract double area();
    }
    static class Circle extends Shape {
        double radius;
        Circle(double r) { this.radius = r; }
        @Override
        double area() { return Math.PI * radius * radius; }
    }
    static class Rectangle extends Shape {
        double width, height;
        Rectangle(double w, double h) { this.width = w; this.height = h; }
        @Override
        double area() { return width * height; }
    }
    static void printArea(Shape s) {
        if (s instanceof Circle)
            System.out.printf("Circle area: %.2f%n", s.area());
        else if (s instanceof Rectangle)
            System.out.printf("Rectangle area: %.1f%n", s.area());
    }
    public static void main(String[] args) {
        Shape[] shapes = { new Circle(5), new Rectangle(4, 3) };
        for (Shape s : shapes) printArea(s);
    }
}
